import { queryExecutionClient } from '@dynatrace-sdk/client-query';
import { eventsClient } from '@dynatrace-sdk/client-classic-environment-v2';

const regionMapping = {
  'West Europe': 'westeurope',
  'East US': 'eastus',
  'East US 2': 'eastus2',
  'West US': 'westus',
  'West US 2': 'westus2',
  'Central US': 'centralus',
  'North Europe': 'northeurope',
  'UK South': 'uksouth',
  'UK West': 'ukwest',
  'Canada Central': 'canadacentral',
  'Canada East': 'canadaeast',
  'Australia East': 'australiaeast',
  'Australia Southeast': 'australiasoutheast',
  'Southeast Asia': 'southeastasia',
  'East Asia': 'eastasia',
  'Japan East': 'japaneast',
  'Japan West': 'japanwest',
  'Brazil South': 'brazilsouth',
  'South Central US': 'southcentralus',
  'North Central US': 'northcentralus',
  'West Central US': 'westcentralus',
  'Germany West Central': 'germanywestcentral',
  'Switzerland North': 'switzerlandnorth',
  'France Central': 'francecentral',
  'Norway East': 'norwayeast',
  'Sweden Central': 'swedencentral'
};

function isVmRelatedService(serviceName) {
  if (!serviceName) return false;
  return serviceName.includes('Virtual Machines') || serviceName.includes('Compute') || serviceName.includes('Dedicated Host');
}

function extractAzurePortalLink(communication) {
  if (!communication) return null;
  const startMarker = 'portal.azure.com';
  const idx = communication.indexOf(startMarker);
  if (idx === -1) return null;
  const startIdx = communication.lastIndexOf('https://', idx);
  if (startIdx === -1) return null;
  let endIdx = communication.indexOf('"', startIdx);
  if (endIdx === -1) endIdx = communication.indexOf(' ', startIdx);
  if (endIdx === -1) endIdx = startIdx + 200;
  return communication.substring(startIdx, endIdx);
}

export default async function () {
  const timeout = 60;
  const summary = {
    timestamp: new Date().toISOString(),
    activeHealthEvents: 0,
    vmRelatedEvents: 0,
    correlationsFound: 0,
    eventsCreated: 0,
    errors: 0
  };

  console.log('Querying active Azure Service Health events...');
  const healthQuery = `
    fetch logs, from: now() - 1h
    | filter log.source == "ServiceHealth"
    | parse content, "JSON:parsed"
    | filter parsed[resultType] == "Active"
    | fieldsAdd
        title = parsed[properties][title],
        service = parsed[properties][service],
        region = parsed[properties][region],
        trackingId = parsed[properties][trackingId],
        incidentType = parsed[properties][incidentType],
        impactStartTime = parsed[properties][impactStartTime],
        communication = parsed[properties][communication],
        stage = parsed[properties][stage],
        isHIR = parsed[properties][isHIR]
    | dedup trackingId
    | fields title, service, region, trackingId, incidentType, impactStartTime, communication, stage, isHIR
  `;

  const healthResponse = await queryExecutionClient.queryExecute({
    body: {
      query: healthQuery,
      requestTimeoutMilliseconds: timeout * 1000,
      fetchTimeoutSeconds: timeout
    }
  });

  const healthEvents = healthResponse.result.records || [];
  summary.activeHealthEvents = healthEvents.length;
  console.log('Found ' + healthEvents.length + ' active health events');

  if (healthEvents.length === 0) {
    console.log('No active health events found. Exiting.');
    return summary;
  }

  const correlations = [];

  for (const event of healthEvents) {
    if (!isVmRelatedService(event.service)) {
      console.log('Skipping non-VM service: ' + event.service);
      continue;
    }

    summary.vmRelatedEvents++;
    const azureRegion = event.region;
    const dtRegion = regionMapping[azureRegion] || (azureRegion ? azureRegion.toLowerCase().replace(/ /g, '') : 'unknown');

    console.log('Processing VM-related event in region ' + azureRegion + ' (' + dtRegion + ')');

    try {
      const entityQuery = `
        fetch dt.entity.azure_vm
        | fieldsAdd azureResourceId, azureResourceGroupName
        | filter contains(azureResourceId, "${dtRegion}")
        | fields entity.name, id, azureResourceId, azureResourceGroupName
        | limit 100
      `;

      const entityResponse = await queryExecutionClient.queryExecute({
        body: {
          query: entityQuery,
          requestTimeoutMilliseconds: timeout * 1000,
          fetchTimeoutSeconds: timeout
        }
      });

      const entities = entityResponse.result.records || [];
      console.log('Found ' + entities.length + ' Azure VMs in region ' + dtRegion);

      for (const entity of entities) {
        correlations.push({
          healthEvent: {
            trackingId: event.trackingId,
            title: event.title,
            service: event.service,
            region: event.region,
            incidentType: event.incidentType,
            stage: event.stage,
            isHIR: event.isHIR,
            impactStartTime: event.impactStartTime,
            azurePortalLink: extractAzurePortalLink(event.communication)
          },
          entity: {
            id: entity.id,
            name: entity['entity.name'],
            resourceGroup: entity.azureResourceGroupName
          }
        });
      }
    } catch (e) {
      console.log('Error querying entities for region ' + dtRegion + ': ' + e.message);
      summary.errors++;
    }
  }

  summary.correlationsFound = correlations.length;
  console.log('Total correlations found: ' + correlations.length);

  if (correlations.length === 0) {
    console.log('No correlations to create. Exiting.');
    return summary;
  }

  const processedCombos = new Set();

  for (const correlation of correlations) {
    const comboKey = correlation.healthEvent.trackingId + '-' + correlation.entity.id;
    if (processedCombos.has(comboKey)) continue;
    processedCombos.add(comboKey);

    try {
      const eventType = correlation.healthEvent.incidentType === 'Incident' ? 'AVAILABILITY_EVENT' : 'CUSTOM_INFO';

      const eventPayload = {
        eventType: eventType,
        title: 'Azure: ' + correlation.healthEvent.title,
        entitySelector: 'entityId("' + correlation.entity.id + '")',
        properties: {
          'azure.health.trackingId': correlation.healthEvent.trackingId,
          'azure.health.service': correlation.healthEvent.service,
          'azure.health.region': correlation.healthEvent.region,
          'azure.health.incidentType': correlation.healthEvent.incidentType,
          'azure.health.stage': correlation.healthEvent.stage || 'Active',
          'azure.health.isHighImpact': String(correlation.healthEvent.isHIR || false),
          'azure.health.impactStartTime': correlation.healthEvent.impactStartTime || '',
          'azure.health.portalLink': correlation.healthEvent.azurePortalLink || '',
          'source': 'Azure Service Health',
          'correlation.type': 'azure-health-entity'
        }
      };

      await eventsClient.createEvent({ body: eventPayload });
      summary.eventsCreated++;
      console.log('Created event for entity ' + correlation.entity.name);

    } catch (e) {
      console.log('Error creating event: ' + e.message);
      summary.errors++;
    }
  }

  console.log('Azure Service Health Correlation Summary: ' + JSON.stringify(summary));
  return summary;
}
